import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "咖啡店在大學西門外那條商店街的盡頭，門面不大，招牌上的字掉了一半漆。二樓是調查媒體借來堆資料的小辦公室，一樓借給學生當自習空間，點一杯飲料就能坐一整個下午。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪推門進去的時候，琴音已經坐在靠窗的位子。桌上擺了兩個便當盒、一壺熱茶，和一台開著文件的筆電。她身後那面白板貼滿了彩色便利貼，是上週某篇查核報告殘留下來的。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "坐。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音沒有多問。她把其中一個便當推到澪面前，掀開蓋子——炸雞、玉子燒、白飯，還有一小格醃蘿蔔。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "妳上次好好吃一頓是什麼時候？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯昨天有吃。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "泡麵不算。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯前天也是泡麵。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有反駁。她坐下，拿起筷子。炸雞還是溫的，外皮微脆。第一口嚥下去的時候，胃像被提醒了自己還存在，絞了一下。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)真的很久沒吃了。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音沒有盯著她吃。她轉過身，把筆電螢幕轉向澪那一側，上面已經開了一個空白的時間軸模板。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "我幫妳拉一條線。妳說，我打。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪一邊吃，一邊把悠真失蹤前後的時間點報出來。琴音的手指在鍵盤上很快地敲，把每個節點排進模板裡，字距整齊，像在幫一份還沒寫完的報告排骨架。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "兩週前。悠真收到學校轉發的「關東青少年睡眠支援計畫」通知。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音的手指停了半拍。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很短。短到如果不是澪剛好在嚼東西、耳朵空著，根本不會注意到。然後她若無其事地繼續打。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "好。兩週前，學校轉發通知。然後呢？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯剛才那一下是什麼？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看了琴音一眼。琴音的表情和平常一樣，溫溫的，沒有任何不對。也許只是她打字打到一半想了別的事。也許是那個計畫名稱太長，她多看了一眼確認有沒有打錯。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)算了。繼續。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "十天前。悠真第一次去東京分部做檢查。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "十天前，初次檢查。那天他回來有跟妳說什麼嗎？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "說「沒什麼，就是填問卷和量血壓」。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音把這句話也打進備註欄。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "七天前傍晚。悠真最後一次被車站監視器拍到，獨自搭車。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "七天前晚上。悠真手機最後定位，在研究中心附近。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "七天前晚上，最後定位，研究中心附近。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音唸了一遍，語氣像在確認，不像在質疑。她把這兩個節點用同一條線連起來，標了顏色。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "失蹤後第一天。悠真的手機傳出一條訊息——「想冷靜幾天」。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "⋯⋯「想冷靜幾天」。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音沒有評論。她把訊息內容打進去，在後面加了一個問號。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "現在。警方還是以自願離家方向調查。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音打完最後一行，靠回椅背，看著螢幕上那條時間軸。從兩週前的通知到七天前的失蹤，中間只有十天。十天裡，一個十五歲的男孩從收到學校通知，到最後出現在研究中心附近，然後消失。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "從通知到失蹤，中間只有十天。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "嗯。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "最後定位在研究中心附近，但警方查的方向是自願離家。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "對。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音沒有說「也許真的是離家」。她只是看著那條線，像在幫澪檢查有沒有漏掉的環節。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這就是琴音。她不會說「妳想太多了」，也不會說「妳是對的」。她只是把東西排好，讓澪自己看。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)如果每個人都像她這樣就好了。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的便當已經吃了大半。她沒有意識到自己什麼時候開始吃快的。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音從袋子裡拿出一包零食，放在桌角——抹茶口味的軟糖，包裝上印著一隻歪歪扭扭的兔子。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "順路買的。悠真每次來辦公室都翻這個。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯謝謝。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看了一眼那包軟糖，喉嚨有點緊。她低頭繼續吃飯，把那點情緒壓回胃裡，和玉子燒一起嚥下去。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這時候，澪的手機響了。螢幕亮起來——編輯組的來電。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪盯著螢幕，筷子還夾著半塊玉子燒。她不想接，但也不想讓它一直響。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音伸手過來，看了一眼來電顯示，然後直接按掉。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "我等一下幫妳回。今天妳不處理這個。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "吃飯。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把手機推到一邊，把玉子燒塞進嘴裡。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音拿起自己那杯飲料喝了一口。澪這才注意到——桌上沒有黑罐咖啡。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "妳今天沒喝那個？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "胃有點不舒服，就改喝茶了。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音搖了搖手裡的綠茶杯，笑了一下，像在解釋一件微不足道的小事。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)她每天都喝黑罐。從大一認識她到現在，沒見她改過。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)胃不舒服也不是不可能。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有追問。她把最後一口飯吃完，放下筷子。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的時間軸還亮著。七天前那個晚上，悠真的手機最後出現在研究中心附近——然後就消失了。隔天，那條「想冷靜幾天」的訊息傳了出來。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)備用眼鏡沒帶。充電器沒帶。零用錢沒拿。遊戲帳號沒登出。搜尋紀錄沒刪。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)這不是一個「想冷靜幾天」的人會做的事。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音把筆電轉回去，存檔。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "我幫妳備份一份到雲端。妳手機裡的預約提醒截圖也傳給我，我一起整理。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "嗯。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音收拾桌面，把空便當盒疊起來。她動作的時候，視線掃過澪放在桌邊的包——包口沒拉好，露出一角反光的東西。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音的目光在那上面停了不到一秒，然後移開了。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)她看到了嗎？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪不確定。那是悠真留給她的小鏡子，便宜，有刮痕，放在包裡不顯眼。琴音就算看到了，也不會知道那是什麼。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音把東西收進袋子，拉上拉鏈，轉頭看澪。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "至少今天晚上，別再一個人亂跑了，好嗎？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的語氣很輕，像在哄一個不肯睡覺的小孩。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "該查的妳都查了。那研究中心，妳打算什麼時候去？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "下午。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "⋯⋯別一個人硬闖。他們那種地方，越正式越難纏。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "琴音看了她一會兒，沒有再說什麼。她站起來，把袋子掛上肩膀。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "有任何事，打給我。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪點頭。琴音走出咖啡店的時候，下午的陽光從門口斜進來，把她的影子拉得很長，像一條安靜的尾巴。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪一個人坐在那裡，看著螢幕上那條時間軸。", background: Background.Chapter_1_Ch1_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)兩週前。十天前。七天前。", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)悠真，你到底走進了什麼地方？", background: Background.Chapter_1_Ch1_Act4_S0, portrait: Portrait.AsakuraMio_Base },
];
